(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[3414],{9110:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>p});const p={key:"v-2ae511dc",path:"/python/lint/",title:"Pylint + PEP8",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Missing DocString",slug:"missing-docstring",children:[]},{level:2,title:"Missing new line",slug:"missing-new-line",children:[]},{level:2,title:"Invalid Data Type",slug:"invalid-data-type",children:[]},{level:2,title:"Invalid Syntax",slug:"invalid-syntax",children:[]},{level:2,title:"Unused Variables",slug:"unused-variables",children:[]},{level:2,title:"Variable Error",slug:"variable-error",children:[]},{level:2,title:"Bad White Space",slug:"bad-white-space",children:[]},{level:2,title:"Too much Local Variable",slug:"too-much-local-variable",children:[]},{level:2,title:"Too much Global Variable",slug:"too-much-global-variable",children:[]},{level:2,title:"Line is too long",slug:"line-is-too-long",children:[]},{level:2,title:"Too many condition branch",slug:"too-many-condition-branch",children:[]},{level:2,title:"Mixing Tabs and Space",slug:"mixing-tabs-and-space",children:[]},{level:2,title:"Too many arguments in function",slug:"too-many-arguments-in-function",children:[]},{level:2,title:"Conflicted variable Name",slug:"conflicted-variable-name",children:[]},{level:2,title:"Incorrect line indentation",slug:"incorrect-line-indentation",children:[]}],filePathRelative:"python/lint/README.md",git:{updatedTime:162676698e4,contributors:[]}}},8836:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>m});var p=a(6252);const e=(0,p.Wm)("h1",{id:"pylint-pep8",tabindex:"-1"},[(0,p.Wm)("a",{class:"header-anchor",href:"#pylint-pep8","aria-hidden":"true"},"#"),(0,p.Uk)(" Pylint + PEP8")],-1),t=(0,p.Wm)("p",null,"มาตรฐานการเขียน Python อย่าง PEP8 ถูกสร้างขึ้นมาเพื่อให้นักพัฒนาอื่นสามารถอ่านโค้ดของเราได้อย่างสะดวก, สนับสนุนการตรวจสอบโค้ดย้อนหลัง, แจ้งเตือนการเรียกใช้งานหรือการเขียนที่ไม่ถูกต้องตามหลักภาษา, และป้องกันการทำงานที่ผิดพลาดเนื่องจากการไม่มีมาตรฐาน",-1),o=(0,p.Wm)("p",null,"โดยมาตรฐานเหล่านี้จะถูกตรวจสอบโดยระบบตรวจสอบโค้ด (หรือที่เรียกว่า Linter) ซึ่งในที่นี้ก็คือ PyLint",-1),l=(0,p.Uk)("สำหรับน้องๆ ที่ต้องการอ่านรายการ PEP8 ทั้งหมด (ซึ่งแนะนำมากๆ ว่าให้อ่าน) ก็สามารถเข้าไปที่ "),c={href:"https://www.python.org/dev/peps/pep-0008/",target:"_blank",rel:"noopener noreferrer"},r=(0,p.Uk)("https://www.python.org/dev/peps/pep-0008/"),i=(0,p.uE)('<hr><h2 id="missing-docstring" tabindex="-1"><a class="header-anchor" href="#missing-docstring" aria-hidden="true">#</a> Missing DocString</h2><p>Docstring คือ comment เพื่อบอกว่าฟังชั่น หรือ โปรแกรมนั้นๆ ทำงานเพื่ออะไร โดยทุก function ละหัวไฟล์ (บรรทัดที่ 1) จะต้องมี docstring กำกับ</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token triple-quoted-string string">&quot;&quot;&quot;\nThis program will print out the &quot;Happy Kumamon&quot; to the world\n&quot;&quot;&quot;</span>\n\n<span class="token keyword">def</span> <span class="token function">happyKumamon</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n  <span class="token triple-quoted-string string">&quot;&quot;&quot;This function will print out the text&quot;&quot;&quot;</span>\n  <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello Kumamon&quot;</span><span class="token punctuation">)</span>\nhappyKumamon<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>โดย DocString ที่ดีนั้น ใน Docstring ต้องอธิบายโปรแกรม จะต้องอธิบายว่าทั้งโปรแกรมนั้นมีหน้าที่อะไร อย่างไรแบบคร่าวๆ<br> สำหรับ DocString ที่อธิบายฟังก์ชั่นนั้น ก็ต้องอธืบายว่าฟังก์ชั้นนั้นทำงานเพื่ออะไร หรือว่ากำลังจะทำอะไรอยู่</p><hr><h2 id="missing-new-line" tabindex="-1"><a class="header-anchor" href="#missing-new-line" aria-hidden="true">#</a> Missing new line</h2><p>เป็นเรื่องของการลืมสร้างบรรทัดใหม่ น้องๆอาจจะไม่เข้าใจ ว่าทำไปทำไม เพื่ออะไร แต่มันเป็นการบอกโปรแกรมว่าบรรทัดสุดท้ายได้หมดแล้ว</p>',9),u=(0,p.Uk)("StackOverflow Reference : "),k={href:"https://stackoverflow.com/questions/729692/why-should-text-files-end-with-a-newline",target:"_blank",rel:"noopener noreferrer"},d=(0,p.Uk)("https://stackoverflow.com/questions/729692/why-should-text-files-end-with-a-newline"),b=(0,p.uE)('<p>โดยที่พวก Text Editor ส่วนใหญ่ จะมีการทำให้อยู่แล้ว</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token triple-quoted-string string">&quot;&quot;&quot;This program will print out the &quot;Happy Kumamon&quot; to the world&quot;&quot;&quot;</span>\n<span class="token keyword">def</span> <span class="token function">happy</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n  <span class="token triple-quoted-string string">&quot;&quot;&quot;This function will print out the text&quot;&quot;&quot;</span>\n  <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello Kumamon&quot;</span><span class="token punctuation">)</span>\nhappy<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token comment"># and leave this line blank</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="invalid-data-type" tabindex="-1"><a class="header-anchor" href="#invalid-data-type" aria-hidden="true">#</a> Invalid Data Type</h2><p>เป็นการบอกว่าไม่สามารถทำการแปลงประเภทตัวแปร (Casting) ได้</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ถ้าหากรับค่า int มันจะแปลงจาก string เป็น int ปกติ ถ้าหากรับค่า string มันจะแปลงไม่ได้ เพราะ string เป็นตัวอักษร เปลี่ยนค่าเป็นตัวเลขไม่ได้นะจ๊ะ</p><hr><h2 id="invalid-syntax" tabindex="-1"><a class="header-anchor" href="#invalid-syntax" aria-hidden="true">#</a> Invalid Syntax</h2><p>การใช้ฟังชั่นที่ใช้ชื่อผิด ใช้ผิดวิธี โมดูลขาด argument หรือ ไม่ได้เรียกโมดูลที่ต้องการใช้มาก่อน</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>ก่อนส่ง น้องๆ ควรที่จะทดสอบการทำงานก่อนหนึ่งครั้งว่าทำงานเหมือนกับที่ต้องการหรือไม่</p><p>การแจ้ง Invalid Syntax นั้นมักเกิดขึ้นตั้งแต่มีการ Compile โค้ด ดังนั้น Python Compiler ก็จะหยุดการรันโค้ดทันที</p></div><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">import</span> math\nvar_x <span class="token operator">=</span> pi<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ซื่ง pi() ไม่ใช่ฟังชั่นใน python หลัก แต่เป็นส่วนหนึ่งของ library ชื่อ math</p><p>ดังนั้น หากจะแก้ให้ถูก จึงต้องใช้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">import</span> math\nvar_x <span class="token operator">=</span> math<span class="token punctuation">.</span>pi<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="unused-variables" tabindex="-1"><a class="header-anchor" href="#unused-variables" aria-hidden="true">#</a> Unused Variables</h2><p>เป็นการประกาศตัวแปร แล้วน้องไม่เคยใช้มันเลย มันอาจจะไม้เป็นไรสำหรับการรัน เพราะก็สามารถรันได้อย่างปกติ แต่มันเปลืองพื้นที่ RAM (เพื่อจองพื้นที่สำหรับ variable นี้) ทำให้ Pylint ด่า</p><p>ซึ่ง การประกาศแล้วไม่ได้ใช้ วิธีแก้ก็คือ ไม่ต้องไปประกาศครับ ง่ายเนอะ</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;Happy&quot;</span>\nvar_x <span class="token operator">=</span> <span class="token number">12</span>\nvar_y <span class="token operator">=</span> <span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var_x <span class="token operator">+</span> var_y<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ซึ่งตัวแปร kumamon ไม่ได้ถูกใช้ในบรรทัดอื่น (นอกจากการประกาศค่า) เป็นการสี้นเปลืองทรัพยากร</p><h2 id="variable-error" tabindex="-1"><a class="header-anchor" href="#variable-error" aria-hidden="true">#</a> Variable Error</h2><p>การตั้งชื่อ Variable แต่ไปชื่อเดียวกันกับชื่อ Module ก็จะทำให้มันงง ว่าต้องการจะเรียก Module ที่ชื่อ math หรือเรียกตัวแปรที่ชื่อว่า math</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">import</span> math\n\nmath <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span> <span class="token comment"># ตั้งชื่อตัวแปรเหมือนชื่อ Module</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>math<span class="token punctuation">.</span>fabs<span class="token punctuation">(</span><span class="token number">20</span> <span class="token operator">-</span> <span class="token number">99</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>หรือ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>aaa <span class="token operator">=</span> <span class="token number">12</span>\nbbb <span class="token operator">=</span> <span class="token number">55</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>aaa <span class="token operator">+</span> bbb<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ซื่งตัวแปร <code>aaa</code> นั้นก็ปกติอยู่หรอก แต่จะให้คนอื่นเค้ามาอ่านด้วยนั้น เป็นเรื่องที่ยากเหลือเกิน ว่าต้วแปรนี้เอาไว้ทำอะไร</p><p>ดังนั้นพี่มงเลยมี Checklist ที่มันน่าจะด่านะครับ 😃</p><table><thead><tr><th></th><th>Type</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td>1</td><td>Short Variable</td><td>ชื่อตัวแปรสั้นเกินไป</td><td>เช่น<br><code>a</code></td></tr><tr><td>2</td><td>Long Variable</td><td>ชื่อตัวแปรยากเกินเหตุ</td><td>เช่น<br> <code>uvuvwevwevwe_onyetenyevwe_ugwemubwen_ossas</code></td></tr><tr><td>3</td><td>Variable Name is the same as function</td><td>ชื่อตัวแปรเหมือนชื่อฟังชั่น</td><td>เช่น<br><code>if</code></td></tr><tr><td>4</td><td>Vague Variable Name</td><td>ตั้งชื่อตัวแปรอย่างง่ายๆ</td><td>เช่น<br><code>aaa</code></td></tr><tr><td>5</td><td>Capitalized Variable</td><td>ตัวแปรที่มีการตั้งเป็นตัวใหญ่ด้านหน้า (การเขียนแบบนี้เอาไว้ใช้สำหรับการเขียนชื่อ class)</td><td>เช่น<br><code>Num_1</code></td></tr><tr><td>6</td><td>Camel Cased Variable</td><td>ตัวแปรที่ใช้การตั้งค่าเป็นตัวใหญ่แบ่งคำ (ซ้ำกับวิธีการตั้งชื่อ function)</td><td>เช่น<br><code>distanceOverTime</code></td></tr><tr><td>7</td><td>All Capitalized Variable (inside function)</td><td>ตัวแปรที่เป็นตัวใหญ่หมดเมื่อประกาศใน Local Variable</td><td>เช่น<br><code>DISTANCE</code></td></tr><tr><td>8</td><td>Weird Variable Name</td><td>ตัวแปรไม่บ่งบอกถึงการใช้งาน</td><td>เช่น<br><code>num_1</code> สำหรับการเก็บค่า <code>distance</code></td></tr></tbody></table><p>ดังนั้น น้องๆจะต้องระวังในการตั้งชื่อนะครับ</p><p>และระบบก็จะไม่แจ้งนะครับ ว่าตัวแปรไหนผิดด้วยสาเหตุใด น้องๆก็ต้องไปดูแล้วทำการแก้ไขด้วยตนเองนะครับ</p><hr><h2 id="bad-white-space" tabindex="-1"><a class="header-anchor" href="#bad-white-space" aria-hidden="true">#</a> Bad White Space</h2><p>การที่มี white space ในจุดที่มันไม่จำเป็น เป็นการทำให้โค้ดของน้องๆสกปรก ไม่ดีเลย</p><p>เช่น (พี่จะแทน space ด้วย · นะครับ จะได้เห็นกันง่ายๆ)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World&quot;</span><span class="token punctuation">)</span>·\nvar_x<span class="token punctuation">,</span>var_y <span class="token operator">=</span> <span class="token number">12</span><span class="token punctuation">,</span><span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var_x<span class="token punctuation">,</span>var_y<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>ในนี้ Pylint จะด่าในบรรทัด <code>print(&quot;Hello World&quot;)*</code> เพระตัว PyLint เห็น Whitespace ในตัวสุดท้ายนั่นเอง</p><p>อีกเหตุการณ์หนึ่งของการเกิด Whitespace ก็คือกด space หรือไม่กด ตามที่ standard เขียนไว้ ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var_x<span class="token punctuation">,</span>var_y <span class="token operator">=</span> <span class="token number">12</span><span class="token punctuation">,</span><span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var_x<span class="token punctuation">,</span>var_y<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ตัว PyLint จะด่า <code>print(var_x,var_y)</code> เพราะ การใช้ , ควรจะเหมือนเขียนภาษาอังกฤษนะครับ ต้องมี space หลัง , อย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var_x<span class="token punctuation">,</span>·var_y <span class="token operator">=</span> <span class="token number">12</span><span class="token punctuation">,</span> <span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var_x<span class="token punctuation">,</span> var_y<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="too-much-local-variable" tabindex="-1"><a class="header-anchor" href="#too-much-local-variable" aria-hidden="true">#</a> Too much Local Variable</h2><p>เป็นก่ารประกาศค่าตัวแปรมากเกินไป เปลืองทั้งทรัพยากร แล้วน้องๆก็ไม่จำเป็นต้องมีมากขนาดนั้นด้วย</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    var_a <span class="token operator">=</span> <span class="token number">12</span>\n    var_b <span class="token operator">=</span> <span class="token number">13</span>\n    var_c <span class="token operator">=</span> <span class="token number">14</span>\n    var_d <span class="token operator">=</span> <span class="token number">15</span>\n    var_e <span class="token operator">=</span> <span class="token number">15</span>\n    var_f <span class="token operator">=</span> <span class="token number">16</span>\n    var_g <span class="token operator">=</span> <span class="token number">17</span>\n    var_h <span class="token operator">=</span> <span class="token number">18</span>\n    var_i <span class="token operator">=</span> <span class="token number">19</span>\n    var_j <span class="token operator">=</span> <span class="token number">20</span>\n    var_k <span class="token operator">=</span> <span class="token number">21</span>\n    var_l <span class="token operator">=</span> <span class="token number">22</span>\n    var_m <span class="token operator">=</span> <span class="token number">23</span>\n\nmain<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>การเก็บข้อมูลแบบนี้ดูเหมือนจะเปลืองทรัพยากรการเก็บข้อมูลมากเลย มันเลยด่านะครับ</p><p>น้องๆควรที่จะใช้ List หรือ Dict แทน เพื่อให้เก็บข้อมูลให้เรียกใช้งานได้มากกว่านี้ครับ</p><h2 id="too-much-global-variable" tabindex="-1"><a class="header-anchor" href="#too-much-global-variable" aria-hidden="true">#</a> Too much Global Variable</h2><p>เหมือนกับข้อที่แล้วเลยจ้า มันเปลืองพื้นที่ (การเก็บตัวแปรเป็นแบบ Global เปลืองทรัพยากรมากกว่า local อีกนะครับ จะบอกให้)</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>VAR_A <span class="token operator">=</span> <span class="token number">12</span>\nVAR_B <span class="token operator">=</span> <span class="token number">13</span>\nVAR_C <span class="token operator">=</span> <span class="token number">14</span>\nVAR_D <span class="token operator">=</span> <span class="token number">15</span>\nVAR_E <span class="token operator">=</span> <span class="token number">15</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>เพราะการเก็บตัวแปรแบบ Global เหมาะกับตัวแปรที่ถูกเปลี่ยนแปลงบ่อย หรือตัวแปรที่ทุก Function ควรรู้ครับ</p><h2 id="line-is-too-long" tabindex="-1"><a class="header-anchor" href="#line-is-too-long" aria-hidden="true">#</a> Line is too long</h2><p>เป็นการบอกว่าโปรแกรมในแถวใดแถวหนึ่งยาวมาก <br> โดยปกติแล้ว โปรแกรมก็ไม่ควรที่จะยาวเกิน <strong>100 ตัวอักษร</strong> อยู่แล้ว เพราะด้วยเหตุผลการอ่านไม่ออกล้วนๆครับ</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;This is a very long string, and they are more than 100 character long. They just keep going and going and going and going and going and going and going and going and going and going&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="too-many-condition-branch" tabindex="-1"><a class="header-anchor" href="#too-many-condition-branch" aria-hidden="true">#</a> Too many condition branch</h2><p>เมื่อน้องต้องการทำ statement ซ้อนกันมาก (Chained IF หรือ Chain Loop) ก็จะโดนด่าแบบนี้ครับ</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>    var_x <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">:</span>\n        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n    <span class="token keyword">else</span><span class="token punctuation">:</span>\n        <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">2</span><span class="token punctuation">:</span>\n            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n        <span class="token keyword">else</span><span class="token punctuation">:</span>\n            <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">3</span><span class="token punctuation">:</span>\n                <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n            <span class="token keyword">else</span><span class="token punctuation">:</span>\n                <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">4</span><span class="token punctuation">:</span>\n                    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                <span class="token keyword">else</span><span class="token punctuation">:</span>\n                    <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">5</span><span class="token punctuation">:</span>\n                        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                    <span class="token keyword">else</span><span class="token punctuation">:</span>\n                        <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">6</span><span class="token punctuation">:</span>\n                            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                        <span class="token keyword">else</span><span class="token punctuation">:</span>\n                            <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">7</span><span class="token punctuation">:</span>\n                                <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                            <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">8</span><span class="token punctuation">:</span>\n                                    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                    <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">9</span><span class="token punctuation">:</span>\n                                        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                    <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                        <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">10</span><span class="token punctuation">:</span>\n                                            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                        <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                            <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">11</span><span class="token punctuation">:</span>\n                                                <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                            <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                                <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">12</span><span class="token punctuation">:</span>\n                                                    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                                <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                                    <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">13</span><span class="token punctuation">:</span>\n                                                        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                                    <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                                        <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">14</span><span class="token punctuation">:</span>\n                                                            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n                                                        <span class="token keyword">else</span><span class="token punctuation">:</span>\n                                                            <span class="token keyword">if</span> var_x <span class="token operator">==</span> <span class="token number">15</span><span class="token punctuation">:</span>\n                                                                <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Var_x is equal to&quot;</span><span class="token punctuation">,</span> var_x<span class="token punctuation">)</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br></div></div><p>หากว่าน้องอยากจะใช้เยอะจริงๆ พี่ก็แนะนำว่าให้น้องใช้หลักการ Function หรือ Recursion แทนนะครับ จะประหยัดบรรทัดโค้ดลงไปได้เยอะเลย</p><h2 id="mixing-tabs-and-space" tabindex="-1"><a class="header-anchor" href="#mixing-tabs-and-space" aria-hidden="true">#</a> Mixing Tabs and Space</h2><p>การใช้ Python น้องๆก็รู้ๆอยู่นะครับ ว่าจะไม่มีการใช้ {} ในการให้โปรแกรมรู้ว่าอยู่ในระดับขั้นตอนไหน<br> ซึ่งการ indent ที่ดี ก็เป็นสี่งจำเป็น เพื่อให้ Python เข้าใจน้องๆนะครับ<br> การ Indent จะใช้เท่ากับการกด space 4 ครั้งครับ ไม่ใช่ Tab<br> เช่น (พี่จะแทนที่ space ด้วย · และ tab ด้วย ⇥ นะครับ)</p><p>อันนี้เป็นตัวอย่างที่ถูกต้องนะครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n····<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Hello world&quot;</span><span class="token punctuation">)</span>\n\nmain<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>อันนี้ผิด</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n⇥   <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;This is a very long string, and they are more than 100 character long. They just keep going and going and going and going and going and going and going and going and going and going&quot;</span><span class="token punctuation">)</span>\n\nmain<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ซึ่งเวลาน้องเห็นบน Text Editor มันจะเหมือนกันมากๆเลย แทบจะดูไม่ออก ดังนั้น น้องต้องระวังนะครับ</p><p>พี่ก็ขอแนะนำให้น้องเปิด Invisible Character หรือน้องก็สามารถเอา mouse ไปลากได้ โดยหากว่าเป็น space น้องๆก็จะเห็นเป็นจุด (°) แต่หากว่าเป็น TAB ก็จะเห็นเป็นลูกศร (⇥) ครับ</p><hr><h2 id="too-many-arguments-in-function" tabindex="-1"><a class="header-anchor" href="#too-many-arguments-in-function" aria-hidden="true">#</a> Too many arguments in function</h2><p>เป็นคำเตือนที่เกิดขึ้นจากว่า น้องทำการเขียน Function และรับ Parameter มากเกิดไปครับ</p><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    var_a <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_b <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_c <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_d <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_e <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_f <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_g <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    var_h <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    <span class="token keyword">return</span> calculate<span class="token punctuation">(</span>var_a<span class="token punctuation">,</span> var_b<span class="token punctuation">,</span> var_c<span class="token punctuation">,</span> var_d<span class="token punctuation">,</span> var_e<span class="token punctuation">,</span> var_f<span class="token punctuation">,</span> var_g<span class="token punctuation">,</span> var_h<span class="token punctuation">)</span>\n\n<span class="token keyword">def</span> <span class="token function">calculate</span><span class="token punctuation">(</span>var_a<span class="token punctuation">,</span> var_b<span class="token punctuation">,</span> var_c<span class="token punctuation">,</span> var_d<span class="token punctuation">,</span> var_e<span class="token punctuation">,</span> var_f<span class="token punctuation">,</span> var_g<span class="token punctuation">,</span> var_h<span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;The answer is&quot;</span><span class="token punctuation">,</span> var_a <span class="token operator">+</span> var_b <span class="token operator">+</span> var_c <span class="token operator">+</span> var_d <span class="token operator">+</span> var_e <span class="token operator">+</span> var_f <span class="token operator">+</span> var_g <span class="token operator">+</span> var_h<span class="token punctuation">)</span>\n\nmain<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><hr><h2 id="conflicted-variable-name" tabindex="-1"><a class="header-anchor" href="#conflicted-variable-name" aria-hidden="true">#</a> Conflicted variable Name</h2><p>โดยจะเกิดขื้นเมื่อต้องการให้ตัวแปรนึงไปเป็นตัวนับ (ซึ่งตัวนับจะถูกลบล้างไป หากมีการใช้งาน) ดังนั้น ตัว PyLint จึงด่าครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>x <span class="token operator">=</span> <span class="token number">12</span>\n<span class="token keyword">for</span> x <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>หากต้องการแก้ไข ให้เปลี่ยนชื่อตัวแปรไม่ให้ซ้อนทับกันครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>x <span class="token operator">=</span> <span class="token number">12</span>\n<span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="incorrect-line-indentation" tabindex="-1"><a class="header-anchor" href="#incorrect-line-indentation" aria-hidden="true">#</a> Incorrect line indentation</h2><p>โดยอันนี้จะเกิดขื้นเมื่อน้องอยากให้ตัวโปรแกรมเหลือบรรทัดน้อยๆ หรือเกิดจากน้องลืมกด ENTER เพื่อเปลี่ยนบรรทัด เช่น<br> แต่โดยปกติแล้ว โปรแกรมจะไม่รันเลย เนื่องจากว่าไม่เข้าใจว่าต้องการทำอะไร<br> แต่สำหรับบางเหตุการนั้น ได้เฉยเลย พี่เลยเขียนไว้ก่อนนะครับ ว่าให้ศึกษาก่อนที่จะ shorthand coding นะจ๊ะ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token comment"># Normally what it should be</span>\n<span class="token keyword">if</span> <span class="token punctuation">(</span>x <span class="token operator">&gt;</span> <span class="token number">12</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span>\n\n<span class="token comment"># This is incorrect way to shorthand if functions</span>\n<span class="token keyword">if</span> <span class="token punctuation">(</span>x <span class="token operator">&gt;</span> <span class="token number">12</span><span class="token punctuation">)</span><span class="token punctuation">:</span> <span class="token keyword">print</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span>\n\n<span class="token comment"># This is correct way to shorthand if function</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>x <span class="token operator">&gt;</span> <span class="token number">12</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Pylint จะด่า เพราะน้องส่งตัวแปรให้กับฟังชั่น calculate มากเกินไป 😦</p><blockquote><p>พี่มงเจอแค่ปัญหาพวกนี้นะครับ ถ้าอันไหนพี่ยังไม่ได้อธิบาย ฝากเขียนไว้ใน Issues ให้พี่ด้วยจ้า</p></blockquote>',88),m={render:function(n,s){const a=(0,p.up)("OutboundLink");return(0,p.wg)(),(0,p.j4)(p.HY,null,[e,t,o,(0,p.Wm)("p",null,[l,(0,p.Wm)("a",c,[r,(0,p.Wm)(a)])]),i,(0,p.Wm)("p",null,[u,(0,p.Wm)("a",k,[d,(0,p.Wm)(a)])]),b],64)}}}}]);